
"use client";

import React, { useState } from 'react';
import Image from 'next/image';
import { ShoppingCart, Save, Camera, Trash2, Edit2, X } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent } from "@/components/ui/card";
import { cn } from '@/lib/utils';

export interface MakeupService {
  id: string;
  name: string;
  price: number;
  description: string;
  imageUrl: string;
}

interface ServiceCardProps {
  service: MakeupService;
  isSupervisor: boolean;
  onUpdate: (service: MakeupService) => void;
  onDelete: (id: string) => void;
}

export function ServiceCard({ service, isSupervisor, onUpdate, onDelete }: ServiceCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedService, setEditedService] = useState(service);

  const handleWhatsApp = () => {
    const phone = "96181000000"; // Replace with real number
    const message = `Hello! I'd like to book the ${service.name} service.\nPrice: $${service.price}\nPayment Method: Whish Money`;
    window.open(`https://wa.me/${phone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  const handleSave = () => {
    onUpdate(editedService);
    setIsEditing(false);
  };

  return (
    <Card className="group overflow-hidden border-none shadow-lg hover:shadow-2xl transition-all duration-500 bg-white rounded-[2rem]">
      <div className="relative h-72 md:h-80 w-full overflow-hidden">
        <Image
          src={service.imageUrl}
          alt={service.name}
          fill
          className="object-cover transition-transform duration-700 group-hover:scale-110"
          data-ai-hint="makeup look"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
        
        {isSupervisor && (
          <div className="absolute top-4 right-4 flex gap-2">
            <Button 
              size="icon" 
              variant="secondary" 
              className="rounded-full shadow-md bg-white/90 hover:bg-white"
              onClick={() => setIsEditing(!isEditing)}
            >
              {isEditing ? <X className="w-4 h-4" /> : <Edit2 className="w-4 h-4" />}
            </Button>
            <Button 
              size="icon" 
              variant="destructive" 
              className="rounded-full shadow-md"
              onClick={() => onDelete(service.id)}
            >
              <Trash2 className="w-4 h-4" />
            </Button>
          </div>
        )}
      </div>

      <CardContent className="p-8">
        {isEditing ? (
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Service Name</label>
              <Input 
                value={editedService.name} 
                onChange={(e) => setEditedService({...editedService, name: e.target.value})} 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Price ($)</label>
              <Input 
                type="number"
                value={editedService.price} 
                onChange={(e) => setEditedService({...editedService, price: Number(e.target.value)})} 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Description</label>
              <Textarea 
                value={editedService.description} 
                onChange={(e) => setEditedService({...editedService, description: e.target.value})} 
                rows={3}
              />
            </div>
            <Button onClick={handleSave} className="w-full gap-2 rounded-xl">
              <Save className="w-4 h-4" /> Update Listing
            </Button>
          </div>
        ) : (
          <div className="flex flex-col h-full">
            <div className="flex justify-between items-start mb-4">
              <h3 className="text-2xl font-headline text-foreground leading-tight">{service.name}</h3>
              <div className="flex flex-col items-end">
                <span className="text-xl font-bold text-primary font-body">${service.price}</span>
              </div>
            </div>
            <p className="text-muted-foreground text-sm leading-relaxed mb-8 flex-grow">
              {service.description}
            </p>
            <Button 
              onClick={handleWhatsApp}
              className="w-full py-7 text-lg rounded-2xl bg-primary hover:bg-accent transition-all duration-300 shadow-xl shadow-primary/20 gap-3 group/btn"
            >
              <ShoppingCart className="w-5 h-5 group-hover/btn:scale-110 transition-transform" />
              Book via WhatsApp
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  );
}
